# Clean A* Pathfinding Implementation

After analyzing the obfuscated code, this is an **A\* pathfinding algorithm** on a 2D grid with diagonal movement support. Here's the clean implementation:

```javascript
// --- Configuration ---
const GRID_WIDTH = 20;
const GRID_HEIGHT = 15;

const config = {
  heuristic: 'manhattan',
  diagonalCost: 1.414,
  straightCost: 1,
  maxIterations: 1000,
  wallProbability: 0.25
};

// --- Grid Generation ---
const grid = [];
for (let y = 0; y < GRID_HEIGHT; y++) {
  grid[y] = [];
  for (let x = 0; x < GRID_WIDTH; x++) {
    grid[y][x] = Math.random() < config.wallProbability ? 1 : 0;
  }
}

const start = { x: 0, y: 0 };
const goal = { x: GRID_WIDTH - 1, y: GRID_HEIGHT - 1 };

// Ensure start and goal are not walls
grid[start.y][start.x] = 0;
grid[goal.y][goal.x] = 0;

// --- Heuristic Function ---
function heuristic(nodeA, nodeB) {
  const dx = Math.abs(nodeA.x - nodeB.x);
  const dy = Math.abs(nodeA.y - nodeB.y);

  if (config.heuristic === 'manhattan') {
    return dx + dy;
  }
  return Math.sqrt(dx * dx + dy * dy);
}

// --- Get Traversable Neighbors ---
function getNeighbors(node) {
  const neighbors = [];
  const directions = [
    { dx:  0, dy: -1, cost: config.straightCost },
    { dx:  0, dy:  1, cost: config.straightCost },
    { dx: -1, dy:  0, cost: config.straightCost },
    { dx:  1, dy:  0, cost: config.straightCost },
    { dx: -1, dy: -1, cost: config.diagonalCost },
    { dx:  1, dy: -1, cost: config.diagonalCost },
    { dx: -1, dy:  1, cost: config.diagonalCost },
    { dx:  1, dy:  1, cost: config.diagonalCost }
  ];

  for (const dir of directions) {
    const nx = node.x + dir.dx;
    const ny = node.y + dir.dy;

    if (nx >= 0 && nx < GRID_WIDTH && ny >= 0 && ny < GRID_HEIGHT && grid[ny][nx] === 0) {
      neighbors.push({ x: nx, y: ny, moveCost: dir.cost });
    }
  }
  return neighbors;
}

// --- Node Key for Map Lookups ---
function nodeKey(node) {
  return node.x + ',' + node.y;
}

// --- A* Pathfinding ---
function findPath(start, goal) {
  const startKey = nodeKey(start);

  const openSet = {};          // nodes still to explore
  const closedSet = {};        // already explored nodes
  const cameFrom = {};         // parent pointers for path reconstruction
  const gScore = {};           // cost from start to node
  const fScore = {};           // gScore + heuristic estimate

  openSet[startKey] = start;
  gScore[startKey] = 0;
  fScore[startKey] = heuristic(start, goal);

  let iterations = 0;

  while (Object.keys(openSet).length > 0 && iterations < config.maxIterations) {
    iterations++;

    // Find the open node with the lowest fScore
    let currentKey = null;
    let lowestF = Infinity;
    for (const key in openSet) {
      if (fScore[key] < lowestF) {
        lowestF = fScore[key];
        currentKey = key;
      }
    }

    const currentNode = openSet[currentKey];

    // Check if we've reached the goal
    if (currentNode.x === goal.x && currentNode.y === goal.y) {
      const path = [currentNode];
      let traceKey = currentKey;
      while (cameFrom[traceKey]) {
        traceKey = cameFrom[traceKey];
        const stored = openSet[traceKey] || closedSet[traceKey] || {
          x: parseInt(traceKey),
          y: parseInt(traceKey.split(',')[1])
        };
        path.push(stored);
      }
      return { path, cost: gScore[currentKey], iterations };
    }

    // Move current node from open to closed
    delete openSet[currentKey];
    closedSet[currentKey] = currentNode;

    // Explore neighbors
    const neighbors = getNeighbors(currentNode);
    for (const neighbor of neighbors) {
      const neighborKey = nodeKey(neighbor);

      if (closedSet[neighborKey]) continue;

      const tentativeG = gScore[currentKey] + neighbor.moveCost;

      if (gScore[neighborKey] === undefined || tentativeG < gScore[neighborKey]) {
        cameFrom[neighborKey] = currentKey;
        gScore[neighborKey] = tentativeG;
        fScore[neighborKey] = tentativeG + heuristic(neighbor, goal);
        openSet[neighborKey] = neighbor;
      }
    }
  }

  // No path found
  return { path: [], cost: Infinity, iterations };
}

// --- Run ---
const result = findPath(start, goal);
console.log('Path length:', result.path.length, 'Cost:', result.cost, 'Iterations:', result.iterations);
```

## Key observations from the deobfuscation:

- **Algorithm**: Standard A* with an open set, closed set, g-scores, f-scores, and parent tracking
- **Grid**: 20×15 with random walls (25% chance per cell)
- **Movement**: 8-directional — cardinal moves cost 1, diagonal moves cost 1.414 (≈√2)
- **Heuristic**: Configurable — Manhattan or Euclidean distance
- **Iteration cap**: 1000 iterations maximum
- **Path reconstruction**: Traces back through parent pointers from goal to start
